from litellm import Router

router = Router(
    model_list=[
        {
            'model_name': 'fast',        # alias used in calls
            'litellm_params': {
                'model': 'openai/gpt-4o-mini',
                'api_key': 'sk-...',
            },
        },
        {
            'model_name': 'smart',
            'litellm_params': {
                'model': 'anthropic/claude-sonnet-5',
                'api_key': 'sk-ant-...',
            },
        },
        {
            'model_name': 'smart',       # fallback for the same alias
            'litellm_params': {
                'model': 'openai/gpt-4o',
                'api_key': 'sk-...',
            },
        },
    ],
    routing_strategy='least-busy',   # or 'simple-shuffle', 'latency-based'
    fallbacks=[{'smart': ['fast']}],  # if 'smart' exhausted, try 'fast'
    num_retries=3,
    retry_after=5,  # seconds between retries
)

response = router.completion(
    model='smart',
    messages=[{'role': 'user', 'content': 'Summarise this document.'}],
)
print(response.choices[0].message.content)

import litellm
import json

# 1. Define tools in the OpenAI schema
tools = [
    {
        'type': 'function',
        'function': {
            'name': 'get_current_weather',
            'description': 'Get the weather for a given city',
            'parameters': {
                'type': 'object',
                'properties': {
                    'city': {'type': 'string'},
                    'unit': {'type': 'string', 'enum': ['celsius', 'fahrenheit']},
                },
                'required': ['city'],
            },
        },
    }
]

# 2. Initial call — model may return a tool_calls list
response = litellm.completion(
    model='openai/gpt-4o-mini',
    messages=[{'role': 'user', 'content': 'What is the weather in Paris?'}],
    tools=tools,
    tool_choice='auto',
)

msg = response.choices[0].message
if msg.tool_calls:
    tool_call = msg.tool_calls[0]
    args = json.loads(tool_call.function.arguments)
    print('Tool called:', tool_call.function.name, args)

    # 3. Run the tool and continue the conversation
    tool_result = {'temperature': 18, 'condition': 'partly cloudy', 'unit': 'celsius'}
    follow_up = litellm.completion(
        model='openai/gpt-4o-mini',
        messages=[
            {'role': 'user', 'content': 'What is the weather in Paris?'},
            msg.model_dump(),  # assistant message with tool_calls
            {
                'role': 'tool',
                'tool_call_id': tool_call.id,
                'content': json.dumps(tool_result),
            },
        ],
        tools=tools,
    )
    print(follow_up.choices[0].message.content)

import litellm
import base64

# Encode a local image to base64
with open('diagram.png', 'rb') as f:
    img_b64 = base64.b64encode(f.read()).decode()

response = litellm.completion(
    model='anthropic/claude-sonnet-5',
    messages=[
        {
            'role': 'user',
            'content': [
                {'type': 'text', 'text': 'Describe what is in this image.'},
                {
                    'type': 'image_url',
                    'image_url': {'url': f'data:image/png;base64,{img_b64}'},
                },
            ],
        }
    ],
)
print(response.choices[0].message.content)
